import scala.collection.immutable.TreeSet

def solve(s: String, order: Array[Long], k: Long): Long = {
    val n = s.length
    val total_substrings = n * (n + 1) / 2
    val tree = TreeSet[Int]()
    var total_without = total_substrings
    for (t <- 0 until n) {
        val current_pos = order(t).toInt
        val left = tree.floor(current_pos)
        val right = tree.ceil(current_pos)
        val original_start = left match {
            case Some(l) => l + 1
            case None => 0
        }
        val original_end = right match {
            case Some(r) => r - 1
            case None => n - 1
        }
        val original_length = original_end - original_start + 1
        val original_contribution = original_length * (original_length + 1) / 2
        total_without -= original_contribution
        // compute left interval
        val new_left_start = original_start
        val new_left_end = current_pos - 1
        if (new_left_start <= new_left_end) {
            val left_length = new_left_end - new_left_start + 1
            val left_contribution = left_length * (left_length + 1) / 2
            total_without += left_contribution
        }
        // compute right interval
        val new_right_start = current_pos + 1
        val new_right_end = original_end
        if (new_right_start <= new_right_end) {
            val right_length = new_right_end - new_right_start + 1
            val right_contribution = right_length * (right_length + 1) / 2
            total_without += right_contribution
        }
        tree += current_pos
        val valid_count = total_substrings - total_without
        if (valid_count >= k) {
            return t.toLong
        }
    }
    -1L
}
